SELECT transcript_id, COUNT(DISTINCT speaker_id) AS num_speakers
FROM speaker_info
GROUP BY transcript_id;

SELECT t.transcript_id, t.duration
FROM transcripts t
WHERE t.duration_seconds > (SELECT AVG(duration_seconds) FROM transcripts);

SELECT transcript_id, AVG(average_duration) AS avg_duration
FROM duration_analysis
GROUP BY transcript_id;

SELECT *
FROM transcripts
ORDER BY upload_date DESC;

SELECT transcript_id, upload_date
FROM transcripts
ORDER BY upload_date DESC;

SELECT * FROM transcripts
ORDER BY words_per_second DESC
LIMIT 10;

SELECT si.*, t.*
FROM speaker_info si
INNER JOIN transcripts t ON si.transcript_id = t.transcript_id;
